import 'package:flutter/material.dart';
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class BiometricAuthExample extends StatefulWidget {
  @override
  _BiometricAuthExampleState createState() => _BiometricAuthExampleState();
}

class _BiometricAuthExampleState extends State<BiometricAuthExample> {
  LocalAuthentication auth = LocalAuthentication();
  SharedPreferences prefs;
  
  // Function to check biometrics availability and perform the authentication.
  void authenticateUser() async {
    bool isAvailable = await auth.canCheckBiometrics;
    
    if (isAvailable) {
      BiometricIdenficationResult result = 
        await auth.authenticate(
          localizedReason: 'Authenticate to continue',
          options: const MethodCallOptions(
            overrideCharacteristics: false, 
            rectSizeFallback: true),
        );
        
      switch (result.status) {
        case BiometricAuthenticationStatus.authorized:
          setState(() {
            _saveAuthStatus(true);   // Save the authentication status in shared preferences
          });
          
          Navigator.of(context).pushReplacementNamed('/home');  // If biometrics are authorized, navigate to home screen.
          break;
        case BiometricAuthenticationStatus.canceled:
          _showDialog('Authenticating cancelled', 'Please try again later.');  
          break;
        case BiometricAuthenticationStatus.failed:
          _showDialog('Failed to authenticate', 'Biometrics could not be verified. Please enter your password'); 
          
          // Fallback to password authentication here or you can choose to close the app as well.
      }
    } else {
        // Biometric methods are not available, proceed with password based authentication.
    }
  }
  
  void _saveAuthStatus(bool status) async {
    prefs = await SharedPreferences.getInstance();
    prefs.setBool('isAuthenticated', status);
  }
  
  void _showDialog(String title, String message) {
     showDialog(
       context: context,
       builder: (BuildContext context) {
         return AlertDialog(
           title: Text(title),
           content: Text(message),
         );
